#include <stdio.h>
#include <string.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        char s[1005]; scanf("%s", s);
        char out[505]; int pos = 0;
        for (int i = 0; i < N; i += 2) {
            if (s[i]=='0' && s[i+1]=='0') out[pos++]='A';
            else if (s[i]=='0' && s[i+1]=='1') out[pos++]='T';
            else if (s[i]=='1' && s[i+1]=='0') out[pos++]='C';
            else out[pos++]='G';
        }
        out[pos]='\0';
        printf("%s\n", out);
    }
    return 0;
}

