#!/usr/bin/env python3
import sys

def encode(s):
    res = []
    for i in range(0, len(s), 2):
        pair = s[i:i+2]
        if pair == '00':
            res.append('A')
        elif pair == '01':
            res.append('T')
        elif pair == '10':
            res.append('C')
        else:
            res.append('G')
    return ''.join(res)

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    idx = 1
    out_lines = []
    for _ in range(t):
        n = int(data[idx]); idx += 1
        s = data[idx]; idx += 1
        out_lines.append(encode(s))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

